draw((0,0)--(1,0)--(1/2,sqrt(3)/2)--cycle);
draw((1,0)--(1+sqrt(3)/2,sqrt(3)/2)--(1/2,sqrt(3)/2));
draw((1+sqrt(3)/2,sqrt(3)/2)--(1+sqrt(3),0)--(1,0));
